  .template-1 .card {
    width: 1080px;
    height: 1080px;
    background: #F6F8F5;
    position: relative;
    overflow: hidden;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
  }

  /* Corner geometric ornaments */
  .template-1 .corner {
    position: absolute;
    width: 160px;
    height: 160px;
  }
  .template-1 .corner svg { width: 100%; height: 100%; }
  .template-1 .corner-tl { top: 0; left: 0; }
  .template-1 .corner-tr { top: 0; right: 0; transform: scaleX(-1); }
  .template-1 .corner-bl { bottom: 0; left: 0; transform: scaleY(-1); }
  .template-1 .corner-br { bottom: 0; right: 0; transform: scale(-1,-1); }

  /* Soft gradient blobs */
  .template-1 .blob {
    position: absolute;
    border-radius: 50%;
    filter: blur(80px);
    opacity: 0.18;
  }
  .template-1 .blob-1 { width: 420px; height: 420px; background: #7BC043; top: -100px; left: -80px; }
  .template-1 .blob-2 { width: 360px; height: 360px; background: #1267B3; bottom: -80px; right: -60px; }

  /* Thin horizontal lines */
  .template-1 .line-top, .template-1 .line-bottom {
    position: absolute;
    left: 80px; right: 80px;
    height: 1px;
    background: linear-gradient(90deg, transparent, #1267B3 30%, #7BC043 70%, transparent);
    opacity: 0.4;
  }
  .template-1 .line-top { top: 100px; }
  .template-1 .line-bottom { bottom: 100px; }

  /* Content */
  .template-1 .content {
    position: relative;
    z-index: 10;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0;
  }

  .template-1 .label-top {
    font-family: 'Poppins', sans-serif;
    font-weight: 500;
    font-size: 17px;
    letter-spacing: 8px;
    color: #1267B3;
    text-transform: uppercase;
    margin-bottom: 32px;
    opacity: 0.8;
  }

  /* Crescent SVG */
  .template-1 .crescent-wrap { margin-bottom: 36px; }

  .template-1 .arabic {
    font-family: 'Cairo', sans-serif;
    font-weight: 700;
    font-size: 87px;
    color: #1267B3;
    line-height: 1;
    margin-bottom: 12px;
    letter-spacing: 2px;
  }

  .template-1 .divider {
    display: flex;
    align-items: center;
    gap: 16px;
    margin: 18px 0;
  }
  .template-1 .divider-line { width: 80px; height: 1px; background: linear-gradient(90deg, transparent, #7BC043); }
  .template-1 .divider-diamond {
    width: 8px; height: 8px;
    background: #7BC043;
    transform: rotate(45deg);
  }

  .template-1 .eid-main {
    font-family: 'Cormorant Garamond', serif;
    font-weight: 600;
    font-size: 100px;
    color: #1267B3;
    line-height: 0.9;
    letter-spacing: 4px;
    text-transform: uppercase;
  }
  .template-1 .eid-main span { color: #7BC043; }

  .template-1 .mubarak {
    font-family: 'Cormorant Garamond', serif;
    font-weight: 500;
    font-style: italic;
    font-size: 60px;
    color: #7BC043;
    letter-spacing: 6px;
    margin-top: 4px;
  }

  .template-1 .subtitle {
    font-family: 'Poppins', sans-serif;
    font-weight: 500;
    font-size: 20px;
    letter-spacing: 3px;
    color: #555;
    margin-top: 32px;
    text-transform: uppercase;
  }

  .template-1 .blessing {
    font-family: 'Cormorant Garamond', serif;
    font-style: italic;
    font-size: 26px;
    color: #888;
    margin-top: 14px;
    text-align: center;
    max-width: 520px;
    line-height: 1.5;
  }

  /* Logo */
  .template-1 .logo-wrap {
    position: absolute;
    bottom: 52px;
    right: 72px;
    display: flex;
    align-items: center;
    gap: 10px;
    opacity: 0.7;
  }
  .template-1 .logo-wrap img { height: 36px; }

  /* Animations */
  @keyframes fadeUp {
    from { opacity: 0; transform: translateY(20px); }
    to { opacity: 1; transform: translateY(0); }
  }
  .template-1 .content > 
  .label-top { animation-delay: 0.1s; }
  .template-1 .crescent-wrap { animation-delay: 0.25s; }
  .template-1 .arabic { animation-delay: 0.4s; }
  .template-1 .divider { animation-delay: 0.5s; }
  .template-1 .eid-main { animation-delay: 0.55s; }
  .template-1 .mubarak { animation-delay: 0.65s; }
  .template-1 .subtitle { animation-delay: 0.75s; }
  .template-1 .blessing { animation-delay: 0.85s; }

.template-1 .card { height: 1350px !important; }



  .template-2 .card {
    width: 1080px;
    height: 1080px;
    position: relative;
    overflow: hidden;
    background: linear-gradient(160deg, #EAF4FF 0%, #F6F8F5 40%, #EDF6E8 100%);
  }

  /* Sky gradient top */
  .template-2 .sky {
    position: absolute;
    top: 0; left: 0; right: 0;
    height: 480px;
    background: linear-gradient(180deg, #1267B3 0%, #2a82d4 30%, #7BC043 70%, transparent 100%);
    opacity: 0.12;
  }

  /* Stars scattered */
  .template-2 .stars {
    position: absolute;
    top: 0; left: 0; right: 0;
    height: 320px;
  }

  /* Mosque silhouette — large, spanning full width bottom half */
  .template-2 .mosque-wrap {
    position: absolute;
    bottom: 300px;
    left: 50%;
    transform: translateX(-50%);
    width: 900px;
  }

  /* Ground stripe */
  .template-2 .ground {
    position: absolute;
    bottom: 280px;
    left: 0; right: 0;
    height: 4px;
    background: linear-gradient(90deg, transparent, #1267B3 20%, #7BC043 80%, transparent);
    opacity: 0.5;
  }

  /* Content above mosque */
  .template-2 .top-content {
    position: absolute;
    top: 80px;
    left: 0; right: 0;
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0;
    z-index: 20;
  }

  .template-2 .crescent-star {
    margin-bottom: 20px;
  }

  .template-2 .arabic-top {
    font-family: 'Cairo', sans-serif;
    font-size: 83px;
    font-weight: 700;
    color: #1267B3;
    letter-spacing: 2px;
    line-height: 1;
  }

  /* Bottom content */
  .template-2 .bottom-content {
    position: absolute;
    bottom: 80px;
    left: 0; right: 0;
    display: flex;
    flex-direction: column;
    align-items: center;
    z-index: 20;
  }

  .template-2 .eid-text {
    font-family: 'Playfair Display', serif;
    font-size: 110px;
    font-weight: 900;
    color: #1267B3;
    line-height: 1;
    letter-spacing: 6px;
  }
  .template-2 .eid-text .green { color: #7BC043; }

  .template-2 .mubarak-text {
    font-family: 'Playfair Display', serif;
    font-weight: 600;
    font-style: italic;
    font-size: 48px;
    color: #7BC043;
    letter-spacing: 8px;
    margin-top: -4px;
  }

  .template-2 .sub-text {
    font-family: 'Poppins', sans-serif;
    font-weight: 500;
    font-size: 18px;
    letter-spacing: 4px;
    color: #666;
    text-transform: uppercase;
    margin-top: 20px;
  }

  .template-2 .blessing-text {
    font-family: 'Poppins', sans-serif;
    font-weight: 500;
    font-size: 21px;
    color: #888;
    margin-top: 10px;
    font-style: italic;
  }

  /* Logo */
  .template-2 .logo-wrap {
    position: absolute;
    bottom: 40px;
    right: 60px;
    z-index: 30;
    opacity: 0.65;
  }
  .template-2 .logo-wrap img { height: 32px; }

  /* Border frame */
  .template-2 .frame {
    position: absolute;
    inset: 24px;
    border: 1px solid rgba(18,103,179,0.15);
    pointer-events: none;
  }
  .template-2 .frame::before {
    content: '';
    position: absolute;
    inset: 6px;
    border: 1px solid rgba(123,192,67,0.12);
  }

  @keyframes fadeUp {
    from { opacity: 0; transform: translateY(16px); }
    to { opacity: 1; transform: translateY(0); }
  }
  .template-2 .top-content > *, .template-2 .bottom-content > 
  .top-content > *:nth-child(1) { animation-delay: 0.1s; }
  .template-2 .top-content > *:nth-child(2) { animation-delay: 0.25s; }
  .template-2 .bottom-content > *:nth-child(1) { animation-delay: 0.4s; }
  .template-2 .bottom-content > *:nth-child(2) { animation-delay: 0.5s; }
  .template-2 .bottom-content > *:nth-child(3) { animation-delay: 0.6s; }
  .template-2 .bottom-content > *:nth-child(4) { animation-delay: 0.7s; }

.template-2 .card { height: 1350px !important; }



  .template-3 .card {
    width: 1080px;
    height: 1080px;
    background: linear-gradient(135deg, #FAFDF7 0%, #F0F8EC 50%, #EDF6FF 100%);
    position: relative;
    overflow: hidden;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
  }

  /* Floral corners — SVG decorations */
  .template-3 .floral-corner { position: absolute; }
  .template-3 .fc-tl { top: 0; left: 0; }
  .template-3 .fc-tr { top: 0; right: 0; transform: scaleX(-1); }
  .template-3 .fc-bl { bottom: 0; left: 0; transform: scaleY(-1); }
  .template-3 .fc-br { bottom: 0; right: 0; transform: scale(-1,-1); }

  /* Floating petals */
  .template-3 .petal { position: absolute; opacity: 0; }
  @keyframes petalFloat {
    0% { opacity: 0; transform: translateY(30px) rotate(0deg); }
    20% { opacity: 0.6; }
    80% { opacity: 0.4; }
    100% { opacity: 0; transform: translateY(-40px) rotate(60deg); }
