    position: relative;
    z-index: 20;
    display: flex;
    flex-direction: column;
    align-items: center;
    text-align: center;
    gap: 0;
  }

  .template-3 .floral-top {
    margin-bottom: 24px;
  }

  .template-3 .eyebrow {
    font-family: 'DM Sans', sans-serif;
    font-weight: 500;
    font-size: 16px;
    letter-spacing: 8px;
    text-transform: uppercase;
    color: #7BC043;
    margin-bottom: 16px;
  }

  .template-3 .arabic {
    font-family: 'Cairo', sans-serif;
    font-weight: 700;
    font-size: 80px;
    color: #1267B3;
    line-height: 1;
    margin-bottom: 8px;
  }

  .template-3 .eid-line {
    font-family: 'DM Serif Display', serif;
    font-size: 90px;
    color: #1267B3;
    line-height: 1;
    letter-spacing: 3px;
  }

  .template-3 .mubarak-line {
    font-family: 'DM Serif Display', serif;
    font-style: italic;
    font-size: 64px;
    color: #7BC043;
    line-height: 1;
    letter-spacing: 2px;
    margin-top: -4px;
  }

  .template-3 .divider {
    margin: 22px 0;
    display: flex;
    align-items: center;
    gap: 16px;
  }
  .template-3 .divider-bar { width: 80px; height: 1px; background: linear-gradient(90deg, transparent, #7BC043 80%); }
  .template-3 .divider-bar.r { background: linear-gradient(90deg, #7BC043 20%, transparent); }
  .template-3 .divider-flower {
    width: 24px;
    height: 24px;
  }

  .template-3 .blessing {
    font-family: 'DM Sans', sans-serif;
    font-weight: 500;
    font-size: 22px;
    color: #555;
    line-height: 1.7;
    max-width: 480px;
    font-style: italic;
  }

  .template-3 .tag-bottom {
    font-family: 'DM Sans', sans-serif;
    font-weight: 600;
    font-size: 16px;
    letter-spacing: 5px;
    text-transform: uppercase;
    color: #1267B3;
    margin-top: 28px;
    opacity: 0.6;
  }

  .template-3 .floral-bottom { margin-top: 24px; }

  /* Logo */
  .template-3 .logo-wrap {
    position: absolute;
    bottom: 40px;
    right: 64px;
    opacity: 0.6;
  }
  .template-3 .logo-wrap img { height: 30px; }

  @keyframes fadeUp {
    from { opacity: 0; transform: translateY(18px); }
    to { opacity: 1; transform: translateY(0); }
  }
  .template-3 .center > 
  .center > *:nth-child(1) { animation-delay: 0.1s; }
  .template-3 .center > *:nth-child(2) { animation-delay: 0.2s; }
  .template-3 .center > *:nth-child(3) { animation-delay: 0.3s; }
  .template-3 .center > *:nth-child(4) { animation-delay: 0.4s; }
  .template-3 .center > *:nth-child(5) { animation-delay: 0.5s; }
  .template-3 .center > *:nth-child(6) { animation-delay: 0.6s; }
  .template-3 .center > *:nth-child(7) { animation-delay: 0.7s; }
  .template-3 .center > *:nth-child(8) { animation-delay: 0.8s; }
  .template-3 .center > *:nth-child(9) { animation-delay: 0.9s; }

.template-3 .card { height: 1350px !important; }



  .template-4 .card {
    width: 1080px;
    height: 1080px;
    background: #F6F8F5;
    position: relative;
    overflow: hidden;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
  }

  /* Background pattern — subtle Arabic-inspired repeat */
  .template-4 .bg-pattern {
    position: absolute;
    inset: 0;
    opacity: 0.025;
    background-image: 
      repeating-linear-gradient(45deg, #1267B3 0, #1267B3 1px, transparent 0, transparent 50%),
      repeating-linear-gradient(-45deg, #7BC043 0, #7BC043 1px, transparent 0, transparent 50%);
    background-size: 40px 40px;
  }

  /* Large faint Arabic text backdrop */
  .template-4 .arabic-backdrop {
    position: absolute;
    font-family: 'Cairo', sans-serif;
    font-size: 320px;
    font-weight: 900;
    color: #1267B3;
    opacity: 0.04;
    white-space: nowrap;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    user-select: none;
    letter-spacing: -10px;
  }

  /* Green accent bar left */
  .template-4 .bar-left {
    position: absolute;
    left: 60px;
    top: 120px;
    bottom: 120px;
    width: 4px;
    background: linear-gradient(180deg, transparent, #7BC043 30%, #7BC043 70%, transparent);
    opacity: 0.6;
  }
  .template-4 .bar-right {
    position: absolute;
    right: 60px;
    top: 120px;
    bottom: 120px;
    width: 4px;
    background: linear-gradient(180deg, transparent, #1267B3 30%, #1267B3 70%, transparent);
    opacity: 0.5;
  }

  /* Ornamental header SVG */
  .template-4 .ornament-top {
    position: absolute;
    top: 70px;
    left: 50%;
    transform: translateX(-50%);
  }
  .template-4 .ornament-bottom {
    position: absolute;
    bottom: 90px;
    left: 50%;
    transform: translateX(-50%);
  }

  /* Content */
