    position: relative;
    z-index: 20;
    display: flex;
    flex-direction: column;
    align-items: center;
    text-align: center;
  }

  .template-4 .arabic-main {
    font-family: 'Cairo', sans-serif;
    font-weight: 900;
    font-size: 130px;
    color: #1267B3;
    line-height: 1;
    letter-spacing: 4px;
    margin-bottom: 4px;
  }

  .template-4 .arabic-sub {
    font-family: 'Cairo', sans-serif;
    font-weight: 500;
    font-size: 44px;
    color: #7BC043;
    letter-spacing: 6px;
    margin-bottom: 28px;
    opacity: 0.9;
  }

  /* Calligraphic divider */
  .template-4 .cal-divider {
    margin-bottom: 28px;
  }

  .template-4 .english-eid {
    font-family: 'Raleway', sans-serif;
    font-weight: 200;
    font-size: 69px;
    color: #1267B3;
    letter-spacing: 16px;
    text-transform: uppercase;
    line-height: 1;
  }

  .template-4 .english-mubarak {
    font-family: 'Raleway', sans-serif;
    font-weight: 600;
    font-size: 83px;
