    border-top: 1px solid rgba(18,103,179,0.15);
    border-bottom: 1px solid rgba(18,103,179,0.15);
  }

  .template-4 .blessing-text {
    font-family: 'Raleway', sans-serif;
    font-weight: 500;
    font-size: 21px;
    color: #666;
    letter-spacing: 2px;
    font-style: italic;
  }

  .template-4 .blessing-text2 {
    font-family: 'Cairo', sans-serif;
    font-weight: 600;
    font-size: 18px;
    color: #1267B3;
    letter-spacing: 1px;
    margin-top: 6px;
    opacity: 0.7;
  }

  /* Logo */
