    from { opacity: 0; transform: translateY(22px); }
    to { opacity: 1; transform: translateY(0); }
  }
  .template-4 .content > 
  .content > *:nth-child(1) { animation-delay: 0.1s; }
  .template-4 .content > *:nth-child(2) { animation-delay: 0.25s; }
  .template-4 .content > *:nth-child(3) { animation-delay: 0.35s; }
